(async function() {
    debugger;
    let className = input1.GetInputValue() || "";
    let classType = input2.GetInputValue() || "";
    let workshopName = input3.GetInputValue() || "";
    // 清空表格
    table1.SetData([]);
    // 切换时空
    let spacetimeid = $Variable.spacetimeGUID;
    const STTYPE_ID = 4; // 时空GUID
    let runInfo = {
        stType: STTYPE_ID,
        spaceTime: spacetimeid
    };
    let changeRes = await changeSpace(runInfo);
    // =================================================================================
    const CLOUDID = Number(location.href.split("GetFileContent")[1].split("/")[1]);
    const SUCCESS_CODE = 0;
    const IDENTIFIERTYPE_NAME = 2; // 对象的标识类型=使用名称标识
    const FU_OBJECT_TYPE = 21001; // APP对象
    const PLAN_THING_RECORD = 4106;
    const APP_NAME = $Variable.APP_NAME; // APP对象的名称
    const FUNC_NAME = "QueryClassData";

    let planThingDatas = [];
    // 1. 获取过滤条件
    let filter = _getFilter();
    // 2. 执行call
    const param = new StringMap({
        type: FU_OBJECT_TYPE,
        cloudID: CLOUDID
    });

    let areaID = 0;
    if (undefined !== areaID) {
        param._insert("areaID", areaID, "int32");
    }

    let inParams = new StringMap({}); // 初始化查询/条件查询/下拉框选项 的入参
    inParams._insert("filter", filter, "string");

    let input = new StringMap({
        identifierType: IDENTIFIERTYPE_NAME,
        name: APP_NAME,
        funcname: FUNC_NAME,
        params: [new Variant(inParams)]
        // params: []
    });

    let res = await Call(param, input);
    if (SUCCESS_CODE !== res.ret) {
        ShowMes("error", `后台服务异常, 获取<班次信息>失败`);
        console.log(`后台服务异常, 获取<班次信息>失败`, res);
        return;
    }
    let data = res.returndata;
    let errorcode = data.errorcode;
    if (SUCCESS_CODE !== errorcode) {
        ShowMes("error", `查询<班次信息>失败,请检查相关时空是否正常运行`);
        console.log(data.errormsg);
    } else {
        planThingDatas = data.statisticslist;
        if (null === planThingDatas || 0 === planThingDatas.length) {
            ShowMes("warning", `查询<班次信息>成功,但无数据返回`);
            return;
        }
    }
    table1.SetData(planThingDatas);

    function _getFilter() {
        let filterArr = [];
        if (className) {
            filterArr.push(`班次名称 include "${className}"`);
        }
        if (classType) {
            filterArr.push(`班次类型 include "${classType}"`);
        }
        if (workshopName) {
            filterArr.push(`车间名称 include "${workshopName}"`);
        }
        let filter = filterArr.join("&&");
        return filter;
    }
    // 切换时空
    function changeSpace(runInfo) {
        return new Promise((resolve) => {
            SetRunInfo(runInfo, function(res) {
                resolve(res);
            });
        });
    }
    // 展示消息提示弹窗
    function ShowMes(type, message) {
        var options = {
            message: message,
            type: type,
            offset: 20,
            duration: 3000,
            showClose: true
        };
        ShowMessage(options);
    }
})();

